def perceive(data):
    text = data if isinstance(data, str) else str(data.get("text", data))
    # Normalize "key: value" and "key:value" into "key value" token pairs.
    tokens = text.replace(",", " ").replace(":", ": ").split()
    hours = 0.0
    category = ""
    pending_key = ""
    for token in tokens:
        if token.endswith(":"):
            pending_key = token[:-1].strip().lower()
            continue
        if pending_key in ("hours", "credits"):
            try:
                hours = float(token)
            except (ValueError, TypeError):
                hours = 0.0
        elif pending_key in ("category", "topic"):
            category = token.strip().lower()
        pending_key = ""
    return {"pending_credits": max(0.0, hours), "last_filing_category": category}
